# --- plot helper (hidden) — the substitution key as a scattered mapping ---
def __map(key):
    return [[i, ord(key[i]) - 97] for i in range(26)]

def __identity():
    return [[i, i] for i in range(26)]

def __plot(key):
    return [
        {"name": "scrambled alphabet (your key)", "points": __map(key), "highlight": True},
        {"name": "no scramble (a=a, b=b, …)", "points": __identity(), "highlight": False},
    ]
